{
  "name": "Year Grid Generator",
  "description": "A customizable year-long contribution graph generator. visualized as a grid. Adjust layouts, colors, and styles to create aesthetic calendar visualizations."
}

export interface AppColors {
  bg: string;
  text: string;
  empty: string;
  fill: string;
}

export interface AppConfig {
  date: string; // YYYY-MM-DD
  mode: 'horizontal' | 'vertical';
  isMondayFirst: boolean;
  showMonths: boolean;
  showDays: boolean;
  dotSize: number;
  gap: number;
  radius: number;
  fontFamily: string;
  colors: AppColors;
}

export interface DayData {
  date: Date;
  dayOfWeek: number;
  month: number;
  filled: boolean;
}

import React, { useMemo } from 'react';
import { AppConfig, DayData } from '../types';

interface YearGridProps {
  config: AppConfig;
  className?: string;
  domRef?: React.RefObject<HTMLDivElement>;
}

const YearGrid: React.FC<YearGridProps> = ({ config, className, domRef }) => {
  const {
    date,
    mode,
    isMondayFirst,
    showMonths,
    showDays,
    dotSize,
    gap,
    radius,
    fontFamily,
    colors
  } = config;

  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  // Labels for the axis
  const dayLabels = isMondayFirst 
    ? ['Mon', '', 'Wed', '', 'Fri', '', ''] 
    : ['', 'Mon', '', 'Wed', '', 'Fri', ''];

  const vDayLabels = isMondayFirst 
    ? ['M','T','W','T','F','S','S'] 
    : ['S','M','T','W','T','F','S'];

  // Calculate grid data
  const { days, startDayOffset } = useMemo(() => {
    const currentDate = new Date(date);
    const year = currentDate.getFullYear();
    const isLeap = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
    const totalDays = isLeap ? 366 : 365;
    const startOfYear = new Date(year, 0, 1);

    // Calculate difference in days for fill logic
    const diffTime = currentDate.getTime() - startOfYear.getTime();
    const currentDayIdx = Math.floor(diffTime / (1000 * 60 * 60 * 24));

    const daysArr: DayData[] = [];
    for (let i = 0; i < totalDays; i++) {
      const d = new Date(year, 0, i + 1);
      daysArr.push({
        date: d,
        dayOfWeek: d.getDay(),
        month: d.getMonth(),
        filled: i <= currentDayIdx
      });
    }

    let offset = daysArr[0].dayOfWeek;
    if (isMondayFirst) {
      offset = offset === 0 ? 6 : offset - 1;
    }

    return { days: daysArr, startDayOffset: offset };
  }, [date, isMondayFirst]);

  // Styles
  const containerStyle: React.CSSProperties = {
    backgroundColor: colors.bg,
    color: colors.text,
    fontFamily: fontFamily,
  };

  const gridStyle: React.CSSProperties = {
    display: 'grid',
    gap: `${gap}px`,
    gridTemplateColumns: mode === 'horizontal' 
      ? `repeat(53, ${dotSize}px)` 
      : `repeat(7, ${dotSize}px)`,
    gridTemplateRows: mode === 'horizontal' 
      ? `repeat(7, ${dotSize}px)` 
      : `repeat(53, ${dotSize}px)`,
    gridAutoFlow: mode === 'horizontal' ? 'column' : 'row',
  };

  const cellStyle = (filled: boolean): React.CSSProperties => ({
    width: `${dotSize}px`,
    height: `${dotSize}px`,
    backgroundColor: filled ? colors.fill : colors.empty,
    borderRadius: `${radius}px`,
  });

  return (
    <div 
      ref={domRef}
      className={`p-12 box-border shadow-2xl inline-block ${className}`}
      style={containerStyle}
    >
      <div className={`flex ${mode === 'horizontal' ? 'flex-col' : 'flex-row'} gap-[${gap * 2}px]`}>

        {/* Horizontal Mode Layout */}
        {mode === 'horizontal' && (
          <>
            {showMonths && (
              <div 
                className="relative h-[14px] mb-1" 
                style={{ 
                  marginBottom: `${gap}px`,
                  marginLeft: showDays ? '24px' : '0' 
                }}
              >
                {monthNames.map((m, i) => (
                  <div
                    key={m}
                    className="absolute text-[10px]"
                    style={{ left: `${i * ((dotSize + gap) * 4.4)}px` }}
                  >
                    {m}
                  </div>
                ))}
              </div>
            )}

            <div className="flex" style={{ gap: `${gap * 2}px` }}>
              {showDays && (
                <div 
                  className="grid gap-[${gap}px]"
                  style={{ 
                    gap: `${gap}px`,
                    gridTemplateRows: `repeat(7, ${dotSize}px)` 
                  }}
                >
                  {dayLabels.map((d, i) => (
                    <div 
                      key={i} 
                      className="text-[9px] text-right flex items-center justify-end"
                      style={{ height: `${dotSize}px` }}
                    >
                      {d}
                    </div>
                  ))}
                </div>
              )}

              <div style={gridStyle}>
                {Array.from({ length: startDayOffset }).map((_, i) => (
                  <div key={`empty-${i}`} />
                ))}
                {days.map((day, i) => (
                  <div
                    key={i}
                    title={day.date.toDateString()}
                    style={cellStyle(day.filled)}
                  />
                ))}
              </div>
            </div>
          </>
        )}

        {/* Vertical Mode Layout */}
        {mode === 'vertical' && (
          <>
            {showMonths && (
              <div 
                className="relative w-[20px]" 
                style={{ marginTop: showDays ? '20px' : '0' }}
              >
                {monthNames.map((m, i) => (
                  <div
                    key={m}
                    className="absolute text-[10px] w-full text-right"
                    style={{ top: `${i * ((dotSize + gap) * 4.4)}px` }}
                  >
                    {m}
                  </div>
                ))}
              </div>
            )}

            <div>
              {showDays && (
                <div 
                  className="grid mb-1"
                  style={{ 
                    gap: `${gap}px`,
                    marginBottom: `${gap}px`,
                    gridTemplateColumns: `repeat(7, ${dotSize}px)`
                  }}
                >
                  {vDayLabels.map((d, i) => (
                    <div 
                      key={i} 
                      className="text-[9px] text-center"
                    >
                      {d}
                    </div>
                  ))}
                </div>
              )}

              <div style={gridStyle}>
                 {Array.from({ length: startDayOffset }).map((_, i) => (
                  <div key={`empty-${i}`} />
                ))}
                {days.map((day, i) => (
                  <div
                    key={i}
                    title={day.date.toDateString()}
                    style={cellStyle(day.filled)}
                  />
                ))}
              </div>
            </div>
          </>
        )}

      </div>
    </div>
  );
};

export default YearGrid;

import React from 'react';
import { AppConfig } from '../types';

interface SidebarProps {
  config: AppConfig;
  setConfig: React.Dispatch<React.SetStateAction<AppConfig>>;
  onDownload: () => void;
  isDownloading: boolean;
}

const Sidebar: React.FC<SidebarProps> = ({ config, setConfig, onDownload, isDownloading }) => {

  const updateConfig = <K extends keyof AppConfig>(key: K, value: AppConfig[K]) => {
    setConfig(prev => ({ ...prev, [key]: value }));
  };

  const updateColor = (key: keyof AppConfig['colors'], value: string) => {
    setConfig(prev => ({ ...prev, colors: { ...prev.colors, [key]: value } }));
  };

  return (
    <aside className="w-full md:w-80 flex-shrink-0 bg-[#111] border-r border-[#222] flex flex-col h-full z-20 shadow-xl overflow-hidden">
      {/* Header */}
      <div className="p-5 border-b border-[#222] flex justify-between items-center bg-[#111]">
        <h1 className="text-sm font-bold tracking-widest uppercase text-white flex items-center gap-2">
          <span className="material-symbols-outlined text-orange-500">calendar_view_week</span>
          Year Grid
        </h1>
        <button 
          onClick={onDownload}
          disabled={isDownloading}
          className="text-xs bg-white text-black px-3 py-1.5 rounded font-bold hover:bg-gray-200 transition-colors uppercase tracking-wider flex items-center gap-1 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <span className="material-symbols-outlined text-[16px]">download</span>
          {isDownloading ? 'Wait...' : 'Save'}
        </button>
      </div>

      {/* Controls */}
      <div className="flex-1 overflow-y-auto p-5 space-y-8 custom-scrollbar">

        {/* Progress Settings */}
        <section className="space-y-3">
          <h2 className="text-[10px] uppercase tracking-widest text-gray-500 font-bold">Progress Settings</h2>
          <div className="space-y-2">
            <label className="text-xs text-gray-400 block">Current Date (Fill up to)</label>
            <input 
              type="date"
              value={config.date}
              onChange={(e) => updateConfig('date', e.target.value)}
              className="w-full bg-[#1a1a1a] border border-[#333] rounded px-3 py-2 text-sm text-white focus:border-orange-500 outline-none transition-colors font-mono"
            />
          </div>
          <div className="flex items-center gap-2">
            <input 
              type="checkbox" 
              id="check-monday"
              checked={config.isMondayFirst}
              onChange={(e) => updateConfig('isMondayFirst', e.target.checked)}
              className="accent-orange-500 w-4 h-4 cursor-pointer"
            />
            <label htmlFor="check-monday" className="text-xs text-gray-400 cursor-pointer">Start week on Monday</label>
          </div>
        </section>

        {/* Layout Settings */}
        <section className="space-y-3">
          <h2 className="text-[10px] uppercase tracking-widest text-gray-500 font-bold">Grid Layout</h2>
          <div className="grid grid-cols-2 gap-2">
            <button 
              onClick={() => updateConfig('mode', 'horizontal')}
              className={`text-xs py-2 rounded border transition-all ${config.mode === 'horizontal' ? 'bg-[#222] text-gray-300 border-[#444]' : 'bg-[#1a1a1a] text-gray-500 border-transparent hover:bg-[#333]'}`}
            >
              Horizontal
            </button>
            <button 
              onClick={() => updateConfig('mode', 'vertical')}
              className={`text-xs py-2 rounded border transition-all ${config.mode === 'vertical' ? 'bg-[#222] text-gray-300 border-[#444]' : 'bg-[#1a1a1a] text-gray-500 border-transparent hover:bg-[#333]'}`}
            >
              Vertical
