        <section className="space-y-3">
          <h2 className="text-[10px] uppercase tracking-widest text-gray-500 font-bold">Labels & Font</h2>
          <div className="flex items-center justify-between">
            <label htmlFor="check-months" className="text-xs text-gray-400 cursor-pointer">Show Month Labels</label>
            <input 
              type="checkbox" id="check-months"
              checked={config.showMonths}
              onChange={(e) => updateConfig('showMonths', e.target.checked)}
              className="accent-orange-500 w-4 h-4 cursor-pointer"
            />
          </div>
          <div className="flex items-center justify-between">
            <label htmlFor="check-days" className="text-xs text-gray-400 cursor-pointer">Show Day Labels</label>
            <input 
              type="checkbox" id="check-days"
              checked={config.showDays}
              onChange={(e) => updateConfig('showDays', e.target.checked)}
              className="accent-orange-500 w-4 h-4 cursor-pointer"
            />
          </div>
          <div className="space-y-1">
            <label className="text-xs text-gray-400 block">Font Family</label>
            <select 
              value={config.fontFamily}
              onChange={(e) => updateConfig('fontFamily', e.target.value)}
              className="w-full bg-[#1a1a1a] border border-[#333] rounded px-2 py-1.5 text-xs text-white outline-none focus:border-orange-500"
            >
              <option value="'Inter', sans-serif">Inter (Sans-Serif)</option>
              <option value="'JetBrains Mono', monospace">JetBrains Mono</option>
              <option value="serif">Serif (Classic)</option>
              <option value="cursive">Handwritten</option>
            </select>
          </div>
        </section>

      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useRef, useEffect } from 'react';
import { AppConfig } from '../types';
import YearGrid from './YearGrid';

interface PreviewAreaProps {
  config: AppConfig;
  gridRef: React.RefObject<HTMLDivElement>;
}

const PreviewArea: React.FC<PreviewAreaProps> = ({ config, gridRef }) => {
  const [zoom, setZoom] = useState(1);
  const containerRef = useRef<HTMLDivElement>(null);

  // Panning state
  const [isPanning, setIsPanning] = useState(false);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const startPos = useRef({ x: 0, y: 0 });

  const handleMouseDown = (e: React.MouseEvent) => {
    if (!containerRef.current) return;
    setIsPanning(true);
    startPos.current = {
      x: e.clientX - position.x,
      y: e.clientY - position.y
    };
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isPanning) return;
    e.preventDefault();
    setPosition({
      x: e.clientX - startPos.current.x,
      y: e.clientY - startPos.current.y
    });
  };

  const handleMouseUp = () => setIsPanning(false);
  const handleMouseLeave = () => setIsPanning(false);

  // Zoom controls
  const handleZoom = (delta: number) => {
    setZoom(prev => Math.max(0.1, Math.min(3.0, prev + delta)));
  };

  const resetZoom = () => {
    setZoom(1);
    setPosition({ x: 0, y: 0 });
  };

  return (
    <main 
      className="flex-1 bg-[#050505] relative flex items-center justify-center overflow-hidden h-full w-full"
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseLeave}
      style={{ cursor: isPanning ? 'grabbing' : 'grab' }}
    >
      {/* Zoom Controls */}
      <div className="absolute bottom-6 right-6 flex gap-2 z-10 select-none" onMouseDown={e => e.stopPropagation()}>
        <button 
          onClick={() => handleZoom(-0.1)}
          className="w-8 h-8 bg-[#222] rounded hover:bg-[#333] text-white flex items-center justify-center border border-[#333] active:scale-95 transition-transform"
        >
          <span className="material-symbols-outlined text-[18px]">remove</span>
        </button>
        <button 
          onClick={resetZoom}
          className="px-3 h-8 bg-[#222] rounded hover:bg-[#333] text-white text-xs font-mono border border-[#333] active:scale-95 transition-transform"
        >
          FIT
        </button>
        <button 
          onClick={() => handleZoom(0.1)}
          className="w-8 h-8 bg-[#222] rounded hover:bg-[#333] text-white flex items-center justify-center border border-[#333] active:scale-95 transition-transform"
        >
          <span className="material-symbols-outlined text-[18px]">add</span>
        </button>
      </div>

      {/* Render Content */}
      <div 
        ref={containerRef}
        className="transition-transform duration-75 ease-out origin-center"
        style={{ 
          transform: `translate(${position.x}px, ${position.y}px) scale(${zoom})`,
        }}
      >
        <YearGrid config={config} domRef={gridRef} />
      </div>
    </main>
  );
};

export default PreviewArea;

import React, { useState, useRef } from 'react';
import Sidebar from './components/Sidebar';
import PreviewArea from './components/PreviewArea';
import { AppConfig } from './types';

// Declare html2canvas for TS since it is loaded via CDN
declare const html2canvas: any;

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig>({
    date: new Date().toISOString().split('T')[0],
    mode: 'horizontal',
    isMondayFirst: false,
    showMonths: true,
    showDays: true,
    dotSize: 14,
    gap: 4,
    radius: 2,
    fontFamily: "'Inter', sans-serif",
    colors: {
      bg: '#0a0a0a',
      text: '#525252',
      empty: '#1f1f1f',
      fill: '#ea580c'
    }
  });

  const gridRef = useRef<HTMLDivElement>(null);
  const [isDownloading, setIsDownloading] = useState(false);

  const handleDownload = async () => {
    if (!gridRef.current || typeof html2canvas === 'undefined') return;

    setIsDownloading(true);
    try {
      // Small delay to allow UI to update if needed
      await new Promise(resolve => setTimeout(resolve, 50));

      const canvas = await html2canvas(gridRef.current, {
        backgroundColor: config.colors.bg,
        scale: 3, // High resolution
        logging: false,
      });

      const link = document.createElement('a');
      link.download = `year-grid-${config.date}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (error) {
      console.error('Download failed:', error);
      alert('Failed to generate image. Please try again.');
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="h-screen flex flex-col md:flex-row bg-[#050505] text-white overflow-hidden">
      <Sidebar 
        config={config} 
        setConfig={setConfig} 
        onDownload={handleDownload}
        isDownloading={isDownloading}
      />
      <PreviewArea config={config} gridRef={gridRef} />
    </div>
  );
};

export default App;

