import React, { useMemo } from 'react';
import { AppConfig, DayData } from '../types';

interface YearGridProps {
  config: AppConfig;
  className?: string;
  domRef?: React.RefObject<HTMLDivElement>;
}

const YearGrid: React.FC<YearGridProps> = ({ config, className, domRef }) => {
  const {
    date,
    mode,
    isMondayFirst,
    showMonths,
    showDays,
    dotSize,
    gap,
    radius,
    fontFamily,
    colors
  } = config;

  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

  const dayLabels = isMondayFirst 
    ? ['Mon', '', 'Wed', '', 'Fri', '', ''] 
    : ['', 'Mon', '', 'Wed', '', 'Fri', ''];

  const vDayLabels = isMondayFirst 
    ? ['M','T','W','T','F','S','S'] 
    : ['S','M','T','W','T','F','S'];

  // Dimensions
  const DAY_LABEL_WIDTH = 24; 
  const DAY_LABEL_HEIGHT = 20;
  const MONTH_LABEL_WIDTH = 28;

  const { days, startDayOffset, monthPositions } = useMemo(() => {
    const currentDate = new Date(date);
    const year = currentDate.getFullYear();
    const isLeap = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
    const totalDays = isLeap ? 366 : 365;
    const startOfYear = new Date(year, 0, 1);

    const diffTime = currentDate.getTime() - startOfYear.getTime();
    const currentDayIdx = Math.floor(diffTime / (1000 * 60 * 60 * 24));

    const daysArr: DayData[] = [];
    for (let i = 0; i < totalDays; i++) {
      const d = new Date(year, 0, i + 1);
      daysArr.push({
        date: d,
        dayOfWeek: d.getDay(),
        month: d.getMonth(),
        filled: i <= currentDayIdx
      });
    }

    let offset = daysArr[0].dayOfWeek;
    if (isMondayFirst) {
      offset = offset === 0 ? 6 : offset - 1;
    }

    // Calculate Exact Month Positions
    const positions: number[] = new Array(12).fill(0);
    const foundMonths = new Set<number>();

    daysArr.forEach((d, i) => {
        if (!foundMonths.has(d.month)) {
            foundMonths.add(d.month);
            // Grid index accounts for the empty start cells
            const gridIndex = i + offset;
            if (mode === 'horizontal') {
                const col = Math.floor(gridIndex / 7);
                positions[d.month] = col * (dotSize + gap);
            } else {
                const row = Math.floor(gridIndex / 7);
                positions[d.month] = row * (dotSize + gap);
            }
        }
    });

    return { days: daysArr, startDayOffset: offset, monthPositions: positions };
  }, [date, isMondayFirst, mode, dotSize, gap]);

  const containerStyle: React.CSSProperties = {
    backgroundColor: colors.bg,
    color: colors.text,
    fontFamily: fontFamily,
  };

  const cellStyle = (filled: boolean): React.CSSProperties => ({
    width: `${dotSize}px`,
    height: `${dotSize}px`,
    backgroundColor: filled ? colors.fill : colors.empty,
    borderRadius: `${radius}px`,
  });

  return (
    <div 
      ref={domRef}
      className={`p-12 box-border shadow-2xl inline-block ${className}`}
      style={containerStyle}
    >
      <div className={`flex ${mode === 'horizontal' ? 'flex-col' : 'flex-row'}`} style={{ gap: `${gap * 2}px` }}>

        {/* ================= HORIZONTAL MODE ================= */}
        {mode === 'horizontal' && (
          <>
            {showMonths && (
              <div 
                className="relative w-full" 
                style={{ 
                  height: '14px',
                  marginBottom: `${gap}px`,
                  // Align months with the grid, skipping day labels column
                  marginLeft: showDays ? `${DAY_LABEL_WIDTH + (gap * 2)}px` : '0px'
                }}
              >
                {monthNames.map((m, i) => (
                  <div
                    key={m}
                    className="absolute text-[10px]"
                    style={{ left: `${monthPositions[i]}px` }}
                  >
                    {m}
                  </div>
                ))}
              </div>
            )}

            <div className="flex" style={{ gap: `${gap * 2}px` }}>
              {showDays && (
                <div 
                  className="grid"
                  style={{ 
                    width: `${DAY_LABEL_WIDTH}px`,
                    gap: `${gap}px`,
                    gridTemplateRows: `repeat(7, ${dotSize}px)` 
                  }}
                >
                  {dayLabels.map((d, i) => (
                    <div 
                      key={i} 
                      className="text-[9px] text-right flex items-center justify-end"
                      style={{ height: `${dotSize}px` }}
                    >
                      {d}
                    </div>
                  ))}
                </div>
              )}

              <div style={{
                display: 'grid',
                gap: `${gap}px`,
                gridTemplateColumns: `repeat(53, ${dotSize}px)`,
                gridTemplateRows: `repeat(7, ${dotSize}px)`,
                gridAutoFlow: 'column',
              }}>
                {Array.from({ length: startDayOffset }).map((_, i) => (
                  <div key={`empty-${i}`} />
                ))}
                {days.map((day, i) => (
                  <div
                    key={i}
                    title={day.date.toDateString()}
                    style={cellStyle(day.filled)}
                  />
                ))}
              </div>
            </div>
          </>
        )}

        {/* ================= VERTICAL MODE ================= */}
        {mode === 'vertical' && (
          <>
            {showMonths && (
              <div 
                className="relative" 
                style={{ 
                    width: `${MONTH_LABEL_WIDTH}px`,
                    // Align months with the grid, skipping day labels header
                    marginTop: showDays ? `${DAY_LABEL_HEIGHT + gap}px` : '0px'
                }}
