import React, { useMemo } from 'react';
import { AppConfig, DayData } from '../types';

interface YearGridProps {
  config: AppConfig;
  className?: string;
  domRef?: React.RefObject<HTMLDivElement>;
}

const YearGrid: React.FC<YearGridProps> = ({ config, className, domRef }) => {
  const {
    date,
    mode,
    granularity,
    itemsPerRow,
    isMondayFirst,
    showMonths,
    showDays,
    showYearLabel,
    dotSize,
    gap,
    radius,
    fontFamily,
    colors,
    transparentBg
  } = config;

  const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

  const dayLabels = isMondayFirst 
    ? ['Mon', '', 'Wed', '', 'Fri', '', ''] 
    : ['', 'Mon', '', 'Wed', '', 'Fri', ''];

  const vDayLabels = isMondayFirst 
    ? ['M','T','W','T','F','S','S'] 
    : ['S','M','T','W','T','F','S'];

  // Dimensions for Day View
  const DAY_LABEL_WIDTH = 24; 
  const DAY_LABEL_HEIGHT = 20;
  const MONTH_LABEL_WIDTH = 28;

  // --- Data Logic ---
  const { dataItems, startDayOffset, monthPositions, year } = useMemo(() => {
    const currentDate = new Date(date);
    const year = currentDate.getFullYear();
    const isLeap = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
    const totalDays = isLeap ? 366 : 365;
    const startOfYear = new Date(year, 0, 1);

    // Normalize date to start of day for comparison
    const currentDayOfYear = Math.floor((currentDate.getTime() - startOfYear.getTime()) / (1000 * 60 * 60 * 24));

    if (granularity === 'day') {
      const daysArr: DayData[] = [];
      for (let i = 0; i < totalDays; i++) {
        const d = new Date(year, 0, i + 1);
        daysArr.push({
          date: d,
          dayOfWeek: d.getDay(),
          month: d.getMonth(),
          filled: i <= currentDayOfYear,
          label: d.toDateString()
        });
      }

      let offset = daysArr[0].dayOfWeek!;
      if (isMondayFirst) {
        offset = offset === 0 ? 6 : offset - 1;
      }

      // Calculate Exact Month Positions for Labels
      const positions: number[] = new Array(12).fill(0);
      const foundMonths = new Set<number>();

      daysArr.forEach((d, i) => {
          if (!foundMonths.has(d.month!)) {
              foundMonths.add(d.month!);
              const gridIndex = i + offset;
              if (mode === 'horizontal') {
                  const col = Math.floor(gridIndex / 7);
                  positions[d.month!] = col * (dotSize + gap);
              } else {
                  const row = Math.floor(gridIndex / 7);
                  positions[d.month!] = row * (dotSize + gap);
              }
          }
      });

      return { dataItems: daysArr, startDayOffset: offset, monthPositions: positions, year };
    } 

    if (granularity === 'week') {
      // ISO-like week calculation (simple version)
      const weeksArr: DayData[] = [];
      const totalWeeks = 53; // Covers partials

      // Determine current week index
      const currentWeekIdx = Math.floor(currentDayOfYear / 7);

      for(let i=0; i < totalWeeks; i++) {
        weeksArr.push({
          filled: i <= currentWeekIdx,
          label: `Week ${i + 1}`,
          // Optional: Add date range
        });
      }
      return { dataItems: weeksArr, startDayOffset: 0, monthPositions: [], year };
    }

    if (granularity === 'month') {
      const monthsArr: DayData[] = [];
      const currentMonthIdx = currentDate.getMonth();

      for(let i=0; i < 12; i++) {
        monthsArr.push({
          filled: i <= currentMonthIdx,
          label: monthNames[i],
        });
      }
      return { dataItems: monthsArr, startDayOffset: 0, monthPositions: [], year };
    }

    return { dataItems: [], startDayOffset: 0, monthPositions: [], year };
  }, [date, isMondayFirst, mode, dotSize, gap, granularity]);

  // --- Styles ---
  const containerStyle: React.CSSProperties = {
    backgroundColor: transparentBg ? 'transparent' : colors.bg,
    color: colors.text,
    fontFamily: fontFamily,
    position: 'relative',
    overflow: 'hidden' // ensure watermark doesn't spill if we decided to make it huge, but generally allow overflow for shadows
  };

  const cellStyle = (filled: boolean): React.CSSProperties => ({
    width: `${dotSize}px`,
    height: `${dotSize}px`,
    backgroundColor: filled ? colors.fill : colors.empty,
    borderRadius: `${radius}px`,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: `${Math.max(8, dotSize * 0.4)}px`,
    color: filled ? colors.bg : colors.text,
    fontWeight: 'bold',
    userSelect: 'none',
    zIndex: 2, // Above watermark
    position: 'relative'
  });

  const watermarkStyle: React.CSSProperties = {
    position: 'absolute',
    top: '50%',
    left: '50%',
    transform: 'translate(-50%, -50%)',
    fontSize: `${Math.max(100, dataItems.length > 20 ? dotSize * 10 : dotSize * 4)}px`,
    fontWeight: 700,
    color: colors.text,
    opacity: 0.05,
    zIndex: 0,
    pointerEvents: 'none',
    whiteSpace: 'nowrap',
  };

  // Wrapper for content to ensure Z-Index works against watermark
  const ContentWrapper = ({ children }: { children: React.ReactNode }) => (
    <div className="relative z-10">{children}</div>
  );

  // --- Render ---

  // 1. DAY VIEW
  if (granularity === 'day') {
    return (
      <div 
        ref={domRef}
        className={`p-12 box-border shadow-2xl inline-block ${className}`}
        style={containerStyle}
      >
        {showYearLabel && <div style={watermarkStyle}>{year}</div>}

        <ContentWrapper>
          <div className={`flex ${mode === 'horizontal' ? 'flex-col' : 'flex-row'}`} style={{ gap: `${gap * 2}px` }}>

            {mode === 'horizontal' && (
              <>
                {showMonths && (
                  <div 
                    className="relative w-full" 
                    style={{ 
                      height: '14px',
                      marginBottom: `${gap}px`,
                      marginLeft: showDays ? `${DAY_LABEL_WIDTH + (gap * 2)}px` : '0px'
                    }}
                  >
                    {monthNames.map((m, i) => (
                      <div
                        key={m}
                        className="absolute text-[10px]"
                        style={{ left: `${monthPositions[i]}px` }}
                      >
                        {m}
                      </div>
                    ))}
                  </div>
                )}

                <div className="flex" style={{ gap: `${gap * 2}px` }}>
                  {showDays && (
                    <div 
                      className="grid"
                      style={{ 
                        width: `${DAY_LABEL_WIDTH}px`,
                        gap: `${gap}px`,
                        gridTemplateRows: `repeat(7, ${dotSize}px)` 
                      }}
                    >
                      {dayLabels.map((d, i) => (
                        <div key={i} className="text-[9px] text-right flex items-center justify-end" style={{ height: `${dotSize}px` }}>{d}</div>
                      ))}
                    </div>
                  )}

                  <div style={{
                    display: 'grid',
                    gap: `${gap}px`,
                    gridTemplateColumns: `repeat(53, ${dotSize}px)`,
                    gridTemplateRows: `repeat(7, ${dotSize}px)`,
                    gridAutoFlow: 'column',
                  }}>
                    {Array.from({ length: startDayOffset }).map((_, i) => <div key={`empty-${i}`} />)}
                    {dataItems.map((day, i) => (
                      <div
                        key={i}
                        title={day.label}
                        style={cellStyle(day.filled)}
                      />
                    ))}
                  </div>
                </div>
              </>
            )}

            {mode === 'vertical' && (
              <>
                {showMonths && (
                  <div 
                    className="relative" 
                    style={{ 
                        width: `${MONTH_LABEL_WIDTH}px`,
                        marginTop: showDays ? `${DAY_LABEL_HEIGHT + gap}px` : '0px'
                    }}
                  >
                    {monthNames.map((m, i) => (
                      <div
                        key={m}
                        className="absolute text-[10px] w-full text-right"
                        style={{ top: `${monthPositions[i]}px` }}
                      >
                        {m}
                      </div>
                    ))}
                  </div>
                )}

                <div>
                  {showDays && (
                    <div 
                      className="grid"
                      style={{ 
                        gap: `${gap}px`,
                        marginBottom: `${gap}px`,
                        gridTemplateColumns: `repeat(7, ${dotSize}px)`
                      }}
                    >
                      {vDayLabels.map((d, i) => (
                        <div key={i} className="text-[9px] text-center flex items-end justify-center" style={{ height: `${DAY_LABEL_HEIGHT}px` }}>{d}</div>
                      ))}
                    </div>
                  )}

                  <div style={{
                    display: 'grid',
                    gap: `${gap}px`,
                    gridTemplateColumns: `repeat(7, ${dotSize}px)`,
                    gridTemplateRows: `repeat(53, ${dotSize}px)`,
                    gridAutoFlow: 'row',
                  }}>
                     {Array.from({ length: startDayOffset }).map((_, i) => <div key={`empty-${i}`} />)}
                     {dataItems.map((day, i) => (
                      <div
                        key={i}
                        title={day.label}
                        style={cellStyle(day.filled)}
                      />
                    ))}
                  </div>
                </div>
              </>
            )}

          </div>
        </ContentWrapper>
      </div>
    );
  }

  // 2. GENERIC GRID VIEW (Week / Month)
  const isHorizontal = mode === 'horizontal';
  const gridStyle: React.CSSProperties = {
    display: 'grid',
    gap: `${gap}px`,
    gridTemplateColumns: isHorizontal ? `repeat(${itemsPerRow}, ${dotSize}px)` : `auto`,
    gridTemplateRows: isHorizontal ? `auto` : `repeat(${itemsPerRow}, ${dotSize}px)`,
    gridAutoFlow: isHorizontal ? 'row' : 'column',
  };

  return (
    <div 
      ref={domRef}
      className={`p-12 box-border shadow-2xl inline-block ${className}`}
      style={containerStyle}
    >
      {showYearLabel && <div style={watermarkStyle}>{year}</div>}

      <ContentWrapper>
        <div style={gridStyle}>
          {dataItems.map((item, i) => (
            <div
              key={i}
              title={item.label}
              style={cellStyle(item.filled)}
            >
              {showMonths && (
                  <span className="pointer-events-none">
                      {granularity === 'month' ? item.label.substring(0, 1) : (granularity === 'week' && dotSize > 20 ? i+1 : '')}
                  </span>
              )}
            </div>
          ))}
        </div>
      </ContentWrapper>
    </div>
  );
};

