  label: string;
  filled: boolean;
  // For Day view specific metadata
  dayOfWeek?: number;
  month?: number;
}

import React, { useState, useRef } from 'react';
import Sidebar from './components/Sidebar';
import PreviewArea from './components/PreviewArea';
import { AppConfig } from './types';

// Declare html2canvas for TS since it is loaded via CDN
declare const html2canvas: any;

const App: React.FC = () => {
  const [config, setConfig] = useState<AppConfig>({
    date: new Date().toISOString().split('T')[0],
    mode: 'horizontal',
    granularity: 'day',
    itemsPerRow: 12,
    isMondayFirst: false,
    showMonths: true,
    showDays: true,
    showYearLabel: true,
    dotSize: 14,
    gap: 4,
    radius: 2,
    fontSize: 10,
    fontFamily: "'Inter', sans-serif",
    colors: {
      bg: '#0a0a0a',
      text: '#525252',
      empty: '#1f1f1f',
      fill: '#ea580c'
    },
    transparentBg: false
  });

  const gridRef = useRef<HTMLDivElement>(null);
  const [isDownloading, setIsDownloading] = useState(false);

  const handleDownload = async () => {
    if (!gridRef.current || typeof html2canvas === 'undefined') return;

    setIsDownloading(true);
    try {
      // Small delay to allow UI to update if needed
      await new Promise(resolve => setTimeout(resolve, 50));

      const canvas = await html2canvas(gridRef.current, {
        backgroundColor: config.transparentBg ? null : config.colors.bg,
        scale: 3, // High resolution
        logging: false,
      });

      const link = document.createElement('a');
      link.download = `year-grid-${config.date}.png`;
      link.href = canvas.toDataURL('image/png');
      link.click();
    } catch (error) {
      console.error('Download failed:', error);
      alert('Failed to generate image. Please try again.');
    } finally {
      setIsDownloading(false);
    }
  };

  return (
    <div className="h-screen flex flex-col md:flex-row bg-[#050505] text-white overflow-hidden">
      <Sidebar 
        config={config} 
        setConfig={setConfig} 
        onDownload={handleDownload}
        isDownloading={isDownloading}
      />
      <PreviewArea config={config} gridRef={gridRef} />
    </div>
  );
};

export default App;

